export class Order {
  id: string;
  status: string; // 'created'|'paid'|'shipped'|'cancelled'|'refunded'
  total: number;
  paidAt: Date | null = null;
  items: OrderItem[] = [];

  // anemic: anyone can set anything
  setStatus(s: string) { this.status = s; }
  setPaidAt(d: Date) { this.paidAt = d; }
}

async function onPaymentSucceeded(orderId: string) {
  const order = await repo.findById(orderId);
  order.setStatus('paid');
  order.setPaidAt(new Date());
  await repo.save(order); // no version check
}

async function cancelOrder(req, res) {
  const order = await repo.findById(req.params.id);
  order.setStatus('cancelled'); // even if shipped!
  await repo.save(order);
  res.json(order);
}

export type OrderStatus = 'created'|'paid'|'shipped'|'cancelled'|'refunded';
const LEGAL: Record<OrderStatus, OrderStatus[]> = {
  created: ['paid','cancelled'],
  paid: ['shipped','refunded'],
  shipped: ['refunded'],
  cancelled: [], refunded: [],
};
export class Order {
  private _events: DomainEvent[] = [];
  constructor(
    readonly id: string,
    private _status: OrderStatus,
    private _total: number,
    private _version: number,
    private _paidAt: Date | null,
  ) {}
  get status(){return this._status;} get version(){return this._version;}
  get paidAt(){return this._paidAt;}
  pullEvents(){const e=this._events;this._events=[];return e;}
  private transition(to: OrderStatus){
    if(!LEGAL[this._status].includes(to)) throw new InvalidTransition(this.id,this._status,to);
    this._status=to; this._version++;
  }
  markPaid(at: Date){
    if(this._status==='paid') return; // idempotent for webhook retries
    this.transition('paid'); this._paidAt=at;
    this._events.push({type:'OrderPaid',orderId:this.id,at});
  }
  ship(){ this.transition('shipped'); this._events.push({type:'OrderShipped',orderId:this.id}); }
  cancel(reason: string){ this.transition('cancelled'); this._events.push({type:'OrderCancelled',orderId:this.id,reason}); }
}

export class InvalidTransition extends Error {
  constructor(public orderId: string, public from: string, public to: string){
    super(`Order ${orderId}: cannot move ${from} -> ${to}`);
    this.name='InvalidTransition';
  }
}

export class OrderRepository {
  constructor(private db: Pool){}
  async findById(id: string): Promise<Order>{
    const r=(await this.db.query('SELECT id,status,total,version,paid_at FROM orders WHERE id=$1',[id])).rows[0];
    return new Order(r.id,r.status,r.total,r.version,r.paid_at);
  }
  async save(o: Order){
    const events=o.pullEvents();
    const c=await this.db.connect();
    try{
      await c.query('BEGIN');
      const res=await c.query('UPDATE orders SET status=$1,paid_at=$2,version=version+1 WHERE id=$3 AND version=$4',[o.status,o.paidAt,o.id,o.version-1]);
      if(res.rowCount===0) throw new ConcurrencyError(o.id);
      for(const e of events) await c.query('INSERT INTO outbox(payload) VALUES($1)',[JSON.stringify(e)]);
      await c.query('COMMIT');
    }catch(e){ await c.query('ROLLBACK'); throw e; } finally { c.release(); }
  }
}

async function cancelOrder(req,res){
  if(!flags.enabled('rich_order_aggregate',req.tenantId)) return legacyCancel(req,res);
  try{
    const order=await repo.findById(req.params.id);
    order.cancel(req.body.reason ?? 'admin');
    await repo.save(order);
    res.json(toV1Json(order)); // preserves flat shape
  }catch(e){
    if(e instanceof InvalidTransition) return res.status(409).json({error:e.message});
    if(e instanceof ConcurrencyError) return res.status(409).json({error:'conflict, retry'});
    throw e;
  }
}

export function splitFee(total: number, ways: number): number[] {
  const each = total / ways;
  return Array(ways).fill(Math.round(each * 100) / 100); // loses remainder
}
export function add(a: number, b: number){ return a + b; } // 0.1+0.2=0.30000000000000004

export function fmt(amount: number, cur: string){
  return cur + ' ' + amount.toFixed(2); // wrong for JPY
}

const EXP: Record<string,number> = { USD:2, EUR:2, GBP:2, JPY:0 };
export class Money {
  private constructor(readonly amountMinor: bigint, readonly currency: string){}
  static fromDecimal(s: string, cur: string){
    const e=EXP[cur]; if(e===undefined) throw new Error('unknown currency '+cur);
    const [w,f='']=s.split('.');
    const frac=(f+'0'.repeat(e)).slice(0,e);
    return new Money(BigInt(w+frac), cur);
  }
  private same(o:Money){ if(o.currency!==this.currency) throw new Error('currency mismatch'); }
  add(o:Money){ this.same(o); return new Money(this.amountMinor+o.amountMinor,this.currency); }
  allocate(ways:number): Money[]{
    const base=this.amountMinor/BigInt(ways);
    let rem=this.amountMinor - base*BigInt(ways);
    return Array.from({length:ways},()=>{
      const extra = rem>0n ? 1n : 0n; rem-=extra;
      return new Money(base+extra,this.currency);
    });
  }
  toDecimal(){ const e=EXP[this.currency]; const s=this.amountMinor.toString().padStart(e+1,'0'); return e===0? s : s.slice(0,-e)+'.'+s.slice(-e); }
}

export function fmt(m: Money){
  return m.currency + ' ' + m.toDecimal();
}

import { Money } from '../domain/money';
export function splitFee(total: Money, ways: number): Money[]{
  const parts=total.allocate(ways);
  // invariant: parts sum exactly to total
  return parts;
}
